using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
            // Existing 500K documents use "Discriminator" — preserve it so they remain queryable
            // both by EF Core and by direct SQL (e.g. WHERE c.Discriminator = 'Product').
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed id generation from "Product|123" to just "123".
            // Existing documents use the compound format — preserve it so FindAsync and
            // point-reads continue to work against existing data.
            entity.HasRootDiscriminatorInJsonId(true);
        });

        // HasIndex was removed: Cosmos DB does not support EF-managed indexes.
        // Manage indexing policy via the Azure Portal, Bicep, or Terraform instead.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

